INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 20, 2, "", "", 320, 0, 10, 0, 23001, 20001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "リリ", "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, 1, 1, 125801, 24001, 40011);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "クリア", "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, 1, 2, 126001, 24001, 40011);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "プレシア", "んーと。\nこれ、あげる。\nはい", 323, 1, 3, 126101, 24001, 40011);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "リリ", "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, 2, 4, 125801, 24001, 40011);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "クリア", "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, 2, 5, 126001, 24001, 40011);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 2, "プレシア", "お兄。\nきてくれて、うれしい", 326, 2, 6, 126101, 24001, 40011);
